"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[11],{3036:e=>{e.exports=JSON.parse('{"functions":[{"name":"new","desc":"Creates a new signal. Optionally annotate it with a type cast to lock in\\nthe `Signature` generic.\\n\\n```lua\\nlocal signal = Signal.new() :: Signal.Signal<(x: number) -> ()>\\n```","params":[],"returns":[{"desc":"","lua_type":"Signal<Signature>"}],"function_type":"static","source":{"line":46,"path":"docs/Signal.lua"}},{"name":"wrap","desc":"Proxies a Roblox `RBXScriptSignal` into a VeSignal. All fires from the\\nRoblox signal are forwarded through the wrapper. Destroying the wrapper also\\ndisconnects the underlying Roblox connection.\\n\\n```lua\\nlocal onTouch = Signal.wrap(workspace.Part.Touched)\\nonTouch:Connect(function(hit) ... end)\\n```","params":[{"name":"rbxSignal","desc":"The Roblox signal to wrap.","lua_type":"RBXScriptSignal"}],"returns":[{"desc":"","lua_type":"Signal<Signature>"}],"function_type":"static","source":{"line":64,"path":"docs/Signal.lua"}},{"name":"any","desc":"Returns a new signal that fires whenever **any** of the given signals fires.\\nThe combined signal re-fires with the same arguments as the triggering input.\\n\\nDestroy the combined signal to clean up all input connections.\\n\\n```lua\\nlocal either = Signal.any(signalA, signalB)\\neither:Connect(function(...) ... end)\\neither:Destroy()\\n```","params":[{"name":"...","desc":"Two or more signals to combine.","lua_type":"Signal<Signature>"}],"returns":[{"desc":"","lua_type":"Signal<Signature>"}],"function_type":"static","source":{"line":84,"path":"docs/Signal.lua"}},{"name":"all","desc":"Returns a new signal that fires once **all** given signals have fired at\\nleast once. Fires with the arguments of the last signal to complete the set.\\nSubsequent fires from any input continue to fire the combined signal.\\n\\n```lua\\nlocal both = Signal.all(playerReady, mapReady)\\nboth:Once(startGame)\\n```","params":[{"name":"...","desc":"Two or more signals to combine.","lua_type":"Signal<Signature>"}],"returns":[{"desc":"","lua_type":"Signal<Signature>"}],"function_type":"static","source":{"line":102,"path":"docs/Signal.lua"}},{"name":"Connect","desc":"Registers a synchronous listener. Listeners with higher `priority` run\\nfirst; the default priority is `0`. Connections with the same priority fire\\nin insertion order.\\n\\n```lua\\nlocal conn = signal:Connect(function(x) print(x) end)\\nconn:Disconnect()\\n```\\n\\n`ConnectSync` is an alias for `Connect`.","params":[{"name":"fn","desc":"The callback to invoke when the signal fires.","lua_type":"Signature"},{"name":"priority","desc":"Dispatch priority. Higher runs first. Default: `0`.","lua_type":"number?"}],"returns":[{"desc":"","lua_type":"Connection<Signature>"}],"function_type":"method","source":{"line":125,"path":"docs/Signal.lua"}},{"name":"ConnectAsync","desc":"Registers a listener that runs in a pooled coroutine thread. The firing\\ncoroutine is not blocked and the listener may yield freely.\\n\\n```lua\\nsignal:ConnectAsync(function(x)\\n    task.wait(1)\\n    doSomething(x)\\nend)\\n```","params":[{"name":"fn","desc":"The callback to invoke in a pooled thread.","lua_type":"Signature"},{"name":"priority","desc":"Dispatch priority. Default: `0`.","lua_type":"number?"}],"returns":[{"desc":"","lua_type":"Connection<Signature>"}],"function_type":"method","source":{"line":145,"path":"docs/Signal.lua"}},{"name":"ConnectIf","desc":"Registers a synchronous listener that only runs when `predicate(...)` returns\\n`true`. The predicate receives the same arguments as the listener.\\n\\n```lua\\nsignal:ConnectIf(\\n    function(player) return player.Team.Name == \\"Red\\" end,\\n    function(player) onRedTeamPlayer(player) end\\n)\\n```","params":[{"name":"predicate","desc":"Called with the fire arguments. Listener runs only when this returns `true`.","lua_type":"(...any) -> boolean"},{"name":"fn","desc":"The callback to invoke when the predicate passes.","lua_type":"Signature"},{"name":"priority","desc":"Dispatch priority. Default: `0`.","lua_type":"number?"}],"returns":[{"desc":"","lua_type":"Connection<Signature>"}],"function_type":"method","source":{"line":166,"path":"docs/Signal.lua"}},{"name":"ConnectIfAsync","desc":"Same as [Signal:ConnectIf] but runs `fn` in a pooled coroutine thread.","params":[{"name":"predicate","desc":"Called with the fire arguments. Listener runs only when this returns `true`.","lua_type":"(...any) -> boolean"},{"name":"fn","desc":"The callback to invoke in a pooled thread.","lua_type":"Signature"},{"name":"priority","desc":"Dispatch priority. Default: `0`.","lua_type":"number?"}],"returns":[{"desc":"","lua_type":"Connection<Signature>"}],"function_type":"method","source":{"line":179,"path":"docs/Signal.lua"}},{"name":"Once","desc":"Registers a listener that automatically disconnects after the first fire.\\n\\n```lua\\nsignal:Once(function(x) print(\\"first fire:\\", x) end)\\n```","params":[{"name":"fn","desc":"The callback to invoke once.","lua_type":"Signature"},{"name":"priority","desc":"Dispatch priority. Default: `0`.","lua_type":"number?"}],"returns":[{"desc":"","lua_type":"Connection<Signature>"}],"function_type":"method","source":{"line":195,"path":"docs/Signal.lua"}},{"name":"OnceAsync","desc":"Same as [Signal:Once] but runs `fn` in a pooled coroutine thread.","params":[{"name":"fn","desc":"The callback to invoke once, in a pooled thread.","lua_type":"Signature"},{"name":"priority","desc":"Dispatch priority. Default: `0`.","lua_type":"number?"}],"returns":[{"desc":"","lua_type":"Connection<Signature>"}],"function_type":"method","source":{"line":207,"path":"docs/Signal.lua"}},{"name":"OnceTimeout","desc":"Registers a once listener with a deadline. If the signal fires before\\n`timeout` seconds, `fn` is called and the connection is removed. If the\\ntimeout expires first, the connection is silently removed and `fn` is\\n**not** called.\\n\\n```lua\\nbuttonPressed:OnceTimeout(function()\\n    openDoor()\\nend, 3)\\n```","params":[{"name":"fn","desc":"The callback to invoke if the signal fires in time.","lua_type":"Signature"},{"name":"timeout","desc":"Seconds to wait before silently disconnecting.","lua_type":"number"},{"name":"priority","desc":"Dispatch priority. Default: `0`.","lua_type":"number?"}],"returns":[{"desc":"","lua_type":"Connection<Signature>"}],"function_type":"method","source":{"line":229,"path":"docs/Signal.lua"}},{"name":"OnceAsyncTimeout","desc":"Same as [Signal:OnceTimeout] but runs `fn` in a pooled coroutine thread.","params":[{"name":"fn","desc":"The callback to invoke in a pooled thread if the signal fires in time.","lua_type":"Signature"},{"name":"timeout","desc":"Seconds to wait before silently disconnecting.","lua_type":"number"},{"name":"priority","desc":"Dispatch priority. Default: `0`.","lua_type":"number?"}],"returns":[{"desc":"","lua_type":"Connection<Signature>"}],"function_type":"method","source":{"line":242,"path":"docs/Signal.lua"}},{"name":"Fire","desc":"Fires the signal. Sync listeners are called directly on the current\\ncoroutine; async listeners (`IsAsync = true`) are dispatched to pooled\\nthreads. This is the recommended default firing method.\\n\\nHas a fast path when `AsyncCount == 0` \u2014 skips all thread machinery.","params":[{"name":"...","desc":"Arguments forwarded to every listener.","lua_type":"any"}],"returns":[],"function_type":"method","source":{"line":258,"path":"docs/Signal.lua"}},{"name":"FireSync","desc":"Calls all listeners synchronously regardless of their `IsAsync` flag. The\\nfastest firing mode. Use when all listeners are sync and re-entrance is not\\nexpected.","params":[{"name":"...","desc":"Arguments forwarded to every listener.","lua_type":"any"}],"returns":[],"function_type":"method","source":{"line":270,"path":"docs/Signal.lua"}},{"name":"FireAsync","desc":"Dispatches every listener to a pooled coroutine thread. Guarantees the\\nfiring coroutine is never blocked, even by sync-registered listeners.","params":[{"name":"...","desc":"Arguments forwarded to every listener.","lua_type":"any"}],"returns":[],"function_type":"method","source":{"line":281,"path":"docs/Signal.lua"}},{"name":"FireDeferred","desc":"Schedules a [Signal:FireSync] on the next `task.defer` cycle. Use to break\\nre-entrance or to guarantee the fire happens after the current frame.","params":[{"name":"...","desc":"Arguments forwarded to every listener.","lua_type":"any"}],"returns":[],"function_type":"method","source":{"line":292,"path":"docs/Signal.lua"}},{"name":"FireSafe","desc":"Fires the signal with per-listener `pcall` protection and deep-copied table\\narguments. Errors are surfaced as `warn` output rather than propagating. Use\\nwhen listeners are untrusted or arguments must not be mutated across\\nlisteners.","params":[{"name":"...","desc":"Arguments deep-copied and forwarded to every listener.","lua_type":"any"}],"returns":[],"function_type":"method","source":{"line":305,"path":"docs/Signal.lua"}},{"name":"Wait","desc":"Yields the current coroutine until the signal fires, then returns the fire\\narguments. Must be called from inside a coroutine or `task` context.\\n\\nIf `timeout > 0` and the signal does not fire in time, the coroutine resumes\\nwith no return values.\\n\\n```lua\\nlocal winner = roundEnded:Wait(60)\\nif winner then\\n    displayWinner(winner)\\nelse\\n    displayDraw()\\nend\\n```","params":[{"name":"timeout","desc":"Maximum seconds to wait. Pass `0` or omit for no timeout.","lua_type":"number"},{"name":"priority","desc":"Dispatch priority for the internal listener. Default: `0`.","lua_type":"number?"}],"returns":[{"desc":"The arguments the signal was fired with, or nothing on timeout.","lua_type":"...any"}],"function_type":"method","source":{"line":332,"path":"docs/Signal.lua"}},{"name":"WaitPriority","desc":"Yields until the signal fires. No timeout. The optional `priority` controls\\nwhere the internal listener is inserted in the queue. Must be called from\\ninside a coroutine or `task` context.","params":[{"name":"priority","desc":"Dispatch priority. Default: `0`.","lua_type":"number?"}],"returns":[{"desc":"The arguments the signal was fired with.","lua_type":"...any"}],"function_type":"method","source":{"line":345,"path":"docs/Signal.lua"}},{"name":"GetListenerCount","desc":"Returns the number of currently active connections.","params":[],"returns":[{"desc":"","lua_type":"number"}],"function_type":"method","source":{"line":357,"path":"docs/Signal.lua"}},{"name":"HasListeners","desc":"Returns `true` if at least one connection is active.","params":[],"returns":[{"desc":"","lua_type":"boolean"}],"function_type":"method","source":{"line":367,"path":"docs/Signal.lua"}},{"name":"DisconnectAll","desc":"Disconnects every active connection and returns all connection objects to\\nthe internal pool. The signal remains usable after this call.","params":[],"returns":[],"function_type":"method","source":{"line":376,"path":"docs/Signal.lua"}},{"name":"Destroy","desc":"Disconnects all listeners, disconnects any proxied `RBXScriptSignal`, and\\nclears the signal table. Do not use the signal after calling this.","params":[],"returns":[],"function_type":"method","source":{"line":385,"path":"docs/Signal.lua"}}],"properties":[],"types":[],"name":"Signal","desc":"Fast, type-safe signals for Roblox.\\n\\nVeSignal provides typed, priority-ordered events with connection pooling,\\nmultiple firing modes, and UDTF-derived type signatures. The `Signature`\\ngeneric propagates to `Fire`, `Wait`, and all connect methods so your IDE\\ncatches argument type errors automatically.\\n\\nRequires the **new Luau type solver** for full generic inference.\\n\\n```lua\\nlocal Signal = require(ReplicatedStorage.VeSignal)\\n\\nlocal onDamage = Signal.new() :: Signal.Signal<(victim: Player, amount: number) -> ()>\\n\\nonDamage:Connect(function(victim, amount)\\n    print(victim.Name, \\"took\\", amount, \\"damage\\")\\nend)\\n\\nonDamage:Fire(player, 25)\\n```","source":{"line":29,"path":"docs/Signal.lua"}}')}}]);